import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintAndEscapeTest {

    private CSVFormat csvFormat;
    private Method printAndEscapeMethod;

    @BeforeEach
    void setUp() throws NoSuchMethodException {
        // Use DEFAULT instance for testing
        csvFormat = CSVFormat.DEFAULT;

        // Access private method printAndEscape via reflection
        printAndEscapeMethod = CSVFormat.class.getDeclaredMethod("printAndEscape", CharSequence.class, int.class, int.class, Appendable.class);
        printAndEscapeMethod.setAccessible(true);
    }

    @Test
    void testPrintAndEscape_NoSpecialChars() throws IOException, InvocationTargetException, IllegalAccessException {
        String input = "simpletext";
        StringBuilder out = new StringBuilder();

        printAndEscapeMethod.invoke(csvFormat, input, 0, input.length(), out);

        // No escaping, output equals input
        assertEquals(input, out.toString());
    }

    @Test
    void testPrintAndEscape_WithDelimiter() throws IOException, InvocationTargetException, IllegalAccessException {
        // Delimiter is ',' in DEFAULT
        String input = "value1,value2";
        StringBuilder out = new StringBuilder();

        printAndEscapeMethod.invoke(csvFormat, input, 0, input.length(), out);

        // The comma should be escaped with escape character (default is DOUBLE_QUOTE_CHAR '"')
        // So expect: value1"",""value2  (escape + delimiter)
        // Actually per code, escape char is '"', delimiter is ','
        // So output: value1"",""value2
        String expected = "value1\"\,value2";
        // But per code, the delimiter char ',' triggers escape append of escape + c
        // So output is: value1"","value2
        // Actually, the code appends escape + c, so " + , => "\","
        // So output: value1"\,"value2
        // Let's build expected string accordingly:
        StringBuilder expectedBuilder = new StringBuilder();
        expectedBuilder.append("value1");
        expectedBuilder.append(csvFormat.getEscapeCharacter());
        expectedBuilder.append(csvFormat.getDelimiter());
        expectedBuilder.append("value2");
        assertEquals(expectedBuilder.toString(), out.toString());
    }

    @Test
    void testPrintAndEscape_WithEscapeChar() throws IOException, InvocationTargetException, IllegalAccessException {
        // Use INFORMIX_UNLOAD which has escape = BACKSLASH '\'
        csvFormat = CSVFormat.INFORMIX_UNLOAD;
        String input = "value\\with\\escapes";
        StringBuilder out = new StringBuilder();

        printAndEscapeMethod.invoke(csvFormat, input, 0, input.length(), out);

        // Each '\' should be escaped as \\ (escape + escape)
        String expected = input.replace("\\", "\\" + csvFormat.getEscapeCharacter());
        assertEquals(expected, out.toString());
    }

    @Test
    void testPrintAndEscape_WithCarriageReturnAndLineFeed() throws IOException, InvocationTargetException, IllegalAccessException {
        String input = "line1\rline2\nline3";
        StringBuilder out = new StringBuilder();

        printAndEscapeMethod.invoke(csvFormat, input, 0, input.length(), out);

        // CR -> \r, LF -> \n with escape char '"'
        // So output should be: line1"rline2"nline3
        StringBuilder expected = new StringBuilder();
        char escape = csvFormat.getEscapeCharacter();
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            if (c == '\r') {
                expected.append(escape).append('r');
            } else if (c == '\n') {
                expected.append(escape).append('n');
            } else {
                expected.append(c);
            }
        }
        assertEquals(expected.toString(), out.toString());
    }

    @Test
    void testPrintAndEscape_Subsequence() throws IOException, InvocationTargetException, IllegalAccessException {
        String input = "abc,def\nghi\rjkl";
        StringBuilder out = new StringBuilder();

        // print only substring "c,def\ng"
        int offset = 2;
        int len = 6;

        printAndEscapeMethod.invoke(csvFormat, input, offset, len, out);

        // The substring is "c,def\ng"
        // ',' and '\n' should be escaped with escape char '"'
        // So output: c","def"ng
        StringBuilder expected = new StringBuilder();
        char escape = csvFormat.getEscapeCharacter();
        int end = offset + len;
        int start = offset;
        int pos = offset;
        while (pos < end) {
            char c = input.charAt(pos);
            if (c == '\r' || c == '\n' || c == csvFormat.getDelimiter() || c == escape) {
                if (pos > start) {
                    expected.append(input, start, pos);
                }
                if (c == '\n') {
                    expected.append(escape).append('n');
                } else if (c == '\r') {
                    expected.append(escape).append('r');
                } else {
                    expected.append(escape).append(c);
                }
                start = pos + 1;
            }
            pos++;
        }
        if (pos > start) {
            expected.append(input, start, pos);
        }

        assertEquals(expected.toString(), out.toString());
    }

    @Test
    void testPrintAndEscape_EmptyInput() throws IOException, InvocationTargetException, IllegalAccessException {
        String input = "";
        StringBuilder out = new StringBuilder();

        printAndEscapeMethod.invoke(csvFormat, input, 0, 0, out);

        assertEquals("", out.toString());
    }

    @Test
    void testPrintAndEscape_OffsetLengthEdgeCases() throws IOException, InvocationTargetException, IllegalAccessException {
        String input = "abc,def";
        StringBuilder out = new StringBuilder();

        // Offset at end, length 0
        printAndEscapeMethod.invoke(csvFormat, input, input.length(), 0, out);
        assertEquals("", out.toString());

        // Offset 0, length 1 (single char, no special char)
        out.setLength(0);
        printAndEscapeMethod.invoke(csvFormat, input, 0, 1, out);
        assertEquals("a", out.toString());

        // Offset 3 (comma), length 1
        out.setLength(0);
        printAndEscapeMethod.invoke(csvFormat, input, 3, 1, out);

        // The comma should be escaped with escape char '"'
        char escape = csvFormat.getEscapeCharacter();
        String expected = escape + String.valueOf(input.charAt(3));
        assertEquals(expected, out.toString());
    }
}
